use std::collections::HashMap;

// This struct holds a reference to data owned by 'data_source' 
// and needs to live as long as that source.
struct Cache<'a> {
    map: HashMap<&'a str, i32>,
}

impl<'a> Cache<'a> {
    fn new(data_source: &'a HashMap<&'a str, i32>) -> Self {
        // We are intentionally taking a reference to the map itself 
        // because we want the cache to share the lifetime of the source data.
        Cache { map: data_source.clone() }
    }

    fn get(&self, key: &str) -> Option<i32> {
        self.map.get(key).cloned()
    }
}

fn main() {
    // 1. Create the long-lived data source.
    let mut source_data: HashMap<&str, i32> = HashMap::new();
    source_data.insert("apple", 1);
    source_data.insert("banana", 2);

    // 2. Create the cache that depends on the lifetime of source_data.
    let shared_cache: Cache = Cache::new(&source_data);

    // 3. Use the cache multiple times, proving its references are valid.
    if let Some(val) = shared_cache.get("apple") {
        println!("Found apple value: {}", val);
    }

    // Because Cache is constructed with a lifetime tied to source_data, 
    // the compiler knows that 'shared_cache' cannot outlive 'source_data'.
}

use std::fmt::{self, Display}; 

// A dummy struct to represent external data
struct Data { 
    value: i32
}

// The function that needs to be taught about non-lexical lifetimes
// Here, the result's lifetime depends on the inputs 'a' and 'b'.
fn print_combined<'a, 'b>(text: &'a str, data: &'b Data) -> String {
    format!("Combined text: {} | Data value: {}", text, data.value)
}

fn main() {
    let my_text = "Hello World";
    let external_data = Data { value: 42 };

    // The compiler needs to know that the returned String lives long enough 
    // based on both 'my_text' and 'external_data'.
    let result = print_combined(my_text, &external_data);
    println!("Result: {}", result);
}

use std::fmt;

// A struct that holds references to multiple things whose lifetimes are coupled.
pub struct CoupledData<'a, 'b> {
    pub owner_ref: &'a str,
    pub related_ref: &'b i32,
}

// This function takes a reference to the whole structure and prints its contents.
fn process_coupled_data<'a, 'b>(data: &'a CoupledData<'a, 'b>) {
    println!("Successfully processed coupled data:\n\tOwner: {}\
\tRelated Value: {}", 
             data.owner_ref, data.related_ref);
}

fn main() {
    let lifetime_source = String::from("This is the primary source of truth.");
    let value_source = 42;

    // The compiler needs to know that 'a and 'b are tied together by the scope 
    // where CoupledData is created, even if they come from different variables.
    let data = CoupledData {
        owner_ref: &lifetime_source,
        related_ref: &value_source,
    };

    // The compiler infers that the lifetime of 'data' must live at least as long 
    // as the shortest life of its components, which is correct here.
    process_coupled_data(&data);
}

fn find_common_elements(slice1: &[i32], slice2: &[i32]) -> Vec<i32> {
    let mut common = Vec::new();
    // We iterate over elements of the first slice.
    for &val in slice1 { 
        if slice2.contains(&val) { 
            common.push(val);
        }
    }
    // Since we are building a new vector, we return ownership of it.
    common
}

fn main() {
    let list_a = [10, 20, 30, 40];
    let list_b = [5, 20, 30, 50];

    // The result 'common' now owns the data.
    let common = find_common_elements(&list_a, &list_b);

    println!("The common elements are: {:?}", common);
}

