// This function simulates returning multiple pieces of data whose lifetimes might overlap.
// We use a tuple containing two &str references, where both references point to data owned by 'source_data'.
fn find_and_return_texts(source_data: &'static str) -> (&'static str, &'static str) {
    let first = "The quick brown fox";
    let second = "jumps over the lazy dog";
    // Because both 'first' and 'second' are string literals ('&'static str), 
    // their lifetimes are known at compile time to be 'static, which is safe here.
    (&first, &second)
}

fn main() {
    let source_data = "This data owns the context";

    // The result of find_and_return_texts returns a tuple of references. 
    // Because we are returning references to string literals (&'static str), 
    // Rust can safely deduce that these lifetimes do not depend on 'source_data', 
    // which is the non-lexical lifetime aspect.
    let (text1, text2) = find_and_return_texts(source_data);

    println!("--- Text Comparison ---");
    println!("Text 1: {}", text1); 
    println!("Text 2: {}", text2); 

    // We can use the original source data too, because its lifetime is independent of the returned references.
    println!("Context Source Data: {}", source_data);
}
